(function (xhr) {
    var XHR = XMLHttpRequest.prototype;

    var open = XHR.open;
    var send = XHR.send;
    var setRequestHeader = XHR.setRequestHeader;

    XHR.open = function (method, url) {
        this._method = method;
        this._url = url;
        this._requestHeaders = {};
        this._startTime = new Date().toISOString();
        this._previous = Date.parse(Date().toString());

        // this.addEventListener("load", function () {
        //     var Url = this._url ? this._url.toLowerCase() : this._url;
        //     console.log("open load Url 1", Url);
        //     if (Url && Url.match("/top_serp/") !== null) {
        //         Url = `https://www.instagram.com${Url}`;
        //         console.log("open load Url", Url);

        //         localStorage.setItem("search-url", Url);
        //         console.log("open XHR Response:", this.responseText);
        //     }
        // });
        return open.apply(this, arguments);
    };

    XHR.setRequestHeader = function (header, value) {
        this._requestHeaders[header] = value;

        return setRequestHeader.apply(this, arguments);
    };

    XHR.send = function () {
        this.addEventListener("load", function () {
            var Url = this._url ? this._url.toLowerCase() : this._url;

            if (Url && Url.match("/top_serp/") !== null) {
                Url = `https://www.instagram.com${Url}`;

                localStorage.setItem("search-url", Url);
                let data = this.responseText;
                data = JSON.parse(data);

                if (data.media_grid.has_more) {
                    localStorage.setItem(
                        "ins-has_next_page",
                        data.media_grid.has_more
                    );
                }
                let temp_data = [];
                if (data.media_grid.sections) {
                    data.media_grid.sections.forEach((element) => {
                        if (
                            element.layout_content &&
                            element.layout_content.medias
                        ) {
                            let tt = element.layout_content.medias;
                            temp_data.push(...tt);
                        }
                    });

                    temp_data = JSON.stringify(temp_data);
                    localStorage.setItem("ins-data", temp_data);
                }
            }

            let claim = this._requestHeaders["X-IG-WWW-Claim"];
            let CSRFToken = this._requestHeaders["X-CSRFToken"];
            let X_ASBD_ID = this._requestHeaders["X-ASBD-ID"];
            let X_IG_App_ID = this._requestHeaders["X-IG-App-ID"];

            if (claim) {
                localStorage.setItem("ins-claim", claim);
            }

            if (claim) {
                localStorage.setItem("ins-claim", claim);
            }
            if (CSRFToken) {
                localStorage.setItem("ins-csrfToken", CSRFToken);
            }
            if (X_ASBD_ID) {
                localStorage.setItem("ins-X_ASBD_ID", X_ASBD_ID);
            }
            if (X_IG_App_ID) {
                localStorage.setItem("ins-X_IG_App_ID", X_IG_App_ID);
            }
        });

        return send.apply(this, arguments);
    };
})(XMLHttpRequest);
